[workspace]
resolver = "2"
members = ["api", "config", "core"]
exclude = ["arceos"]

[workspace.package]
version = "0.1.0"
edition = "2024"
authors = [
    "Azure-stars <Azure_stars@126.com>",
    "Yuekai Jia <equation618@gmail.com>",
]
homepage = "https://github.com/arceos-org/arceos"
repository = "https://github.com/arceos-org/starry-next"

[workspace.dependencies]
axfeat = { path = "arceos/api/axfeat", features = [
    "alloc-slab",
    "page-alloc-4g",
    "fs",
    "fp_simd",
    "irq",
    "lwext4_rs",
    "multitask",
    "net",
    "sched_rr",
    "smp",
] }

axalloc = { path = "arceos/modules/axalloc" }
axconfig = { path = "arceos/modules/axconfig" }
axdriver = { path = "arceos/modules/axdriver" }
axfs-ng = { path = "arceos/modules/axfs-ng" }
axhal = { path = "arceos/modules/axhal", features = ["uspace", "rtc"] }
axlog = { path = "arceos/modules/axlog" }
axmm = { path = "arceos/modules/axmm" }
axnet = { path = "arceos/modules/axnet" }
axruntime = { path = "arceos/modules/axruntime" }
axsync = { path = "arceos/modules/axsync" }
axtask = { path = "arceos/modules/axtask", features = ["task-ext"] }

axfs-ng-vfs = { git = "https://github.com/Starry-Mix-THU/axfs-ng-vfs", rev = "0247038" }
axprocess = { git = "https://github.com/Starry-Mix-THU/axprocess.git", rev = "1666809" }
axsignal = { git = "https://github.com/Starry-Mix-THU/axsignal.git", rev = "65d2c6e" }

axerrno = "0.1"
bitflags = "2.6"
cfg-if = "1.0"
extern-trait = "0.2"
linkme = "0.3.33"
linux-raw-sys = { version = "0.9.3", default-features = false, features = [
    "no_std",
    "general",
    "net",
    "prctl",
    "system",
] }
memory_addr = "0.4"
scope-local = "0.1"
spin = "0.9"

starry-config = { path = "./config" }
starry-core = { path = "./core" }
starry-api = { path = "./api" }

[package]
name = "starry"
version.workspace = true
edition.workspace = true
authors.workspace = true
homepage.workspace = true
repository.workspace = true

[features]
lwext4_rs = ["axfeat/lwext4_rs"]

[dependencies]
axfeat.workspace = true

axconfig.workspace = true
axfs-ng.workspace = true
axhal.workspace = true
axlog.workspace = true
axruntime.workspace = true
axsync.workspace = true
axtask.workspace = true

axprocess.workspace = true
axsignal.workspace = true

axerrno.workspace = true
axfs-ng-vfs.workspace = true
linkme.workspace = true
linux-raw-sys.workspace = true

starry-config.workspace = true
starry-core.workspace = true
starry-api.workspace = true

shlex = { version = "1.3.0", default-features = false }
syscalls = { git = "https://github.com/jasonwhite/syscalls.git", rev = "92624de", default-features = false }

[patch.'https://github.com/oscomp/arceos.git']
axhal = { path = "arceos/modules/axhal" }

[patch.'https://github.com/Starry-Mix-THU/lwext4_rust']
lwext4_rust = { path = "vendor/lwext4_rust" }

[patch.'https://github.com/Starry-Mix-THU/axsignal.git']
axsignal = { path = "vendor/axsignal" }

[patch.crates-io]
# 使用本地 vendor 副本，避免修改后的 vendored crate 继续触发 checksum 校验。
sbi-spec = { path = "vendor/sbi-spec" }
clang-sys = { path = "vendor/clang-sys" }
loongArch64 = { path = "vendor/loongArch64" }
page_table_entry = { path = "vendor/page_table_entry" }
page_table_multiarch = { path = "vendor/page_table_multiarch" }
proc-macro-error2 = { path = "vendor/proc-macro-error2" }
zerocopy = { path = "vendor/zerocopy" }

[package.metadata.vendor-filter]
platforms = ["riscv64gc-unknown-none-elf", "loongarch64-unknown-none"]

//! Starry Mix OS 内核入口点
//!
//! 本文件是操作系统的主入口，负责初始化内核环境、挂载文件系统、
//! 并启动用户态的 init 进程来运行测试脚本。

// ============================================================================
// 全局属性配置
// ============================================================================

#![no_std]
// 禁用标准库链接。
// 内核运行在裸机环境，没有操作系统支持，因此无法使用 std（文件系统、线程等）。
// 只能使用 core 库（基本类型、运算等无 OS 依赖的功能）。

#![no_main]
// 禁用标准 main() 入口。
// 内核由 ArceOS runtime (axruntime) 提供启动流程，从汇编入口直接跳转到 Rust。
// 标准的 std::rt::lang_start 包装器不存在。

#![doc = include_str!("../README.md")]
// 将 README.md 内容作为 crate 文档首页。
// 运行 `cargo doc` 时，生成的文档首页会显示 README 内容。

// ============================================================================
// 外部 crate 声明
// ============================================================================

#[macro_use]
extern crate axlog;
// 引入 axlog 日志库，并导入其宏（如 info!, warn!, error! 等）。
// #[macro_use] 使得这些宏在当前模块及其子模块中可直接使用。

extern crate alloc;
// 引入 alloc 库，提供动态内存分配功能。
// 包含 String、Vec、Box、Arc 等堆分配类型。
// 注意：alloc 需要#[global_allocator] 提供，在 axalloc 模块中配置。

extern crate axruntime;
// 引入 ArceOS 运行时库。
// 提供内核启动流程：从汇编入口 → axruntime::init → 调用本文件的 main()。

// ============================================================================
// 导入依赖
// ============================================================================

use alloc::{format, string::ToString, vec::Vec};
use axfs_ng::FS_CONTEXT;
use axfs_ng_vfs::NodePermission;
// 从 alloc 库导入字符串相关工具。
// format! 用于格式化字符串，ToString trait 用于类型转字符串。

use starry_core::mm::insert_elf_cache;
// 导入 ELF 缓存插入函数。
// 用于预加载常用 ELF 文件到内存缓存，加速后续加载。

// ============================================================================
// 内部模块声明
// ============================================================================

mod entry;
// 用户态应用程序启动模块。
// 提供 run_user_app() 函数，负责加载 ELF、创建进程/线程、启动执行。

mod mm;
// 内存管理辅助模块。
// 处理内核态与用户态内存映射相关操作。

mod syscall;
// 系统调用处理模块。
// 用户态程序通过 syscall 请求内核服务（如 read、write、fork 等）。

// ============================================================================
// ELF 预缓存配置
// ============================================================================

/// 预缓存 ELF 文件列表（riscv64 架构）
///
/// 这些是启动测试脚本时频繁使用的 ELF 文件，预加载可避免重复解析：
/// - `/musl/busybox` - musl libc 版本的 busybox 工具集
/// - `/glibc/busybox` - glibc 版本的 busybox

#![no_std]
#![allow(missing_docs)]

#[macro_use]
extern crate axlog;
extern crate alloc;

pub mod file;
pub mod ptr;
pub mod signal;
pub mod socket;
pub mod time;

mod imp;
pub use imp::*;

//! The core functionality of a monolithic kernel, including loading user
//! programs and managing processes.

#![no_std]
#![warn(missing_docs)]

#[macro_use]
extern crate axlog;
extern crate alloc;

pub mod futex;
pub mod mm;
pub mod resources;
pub mod task;
mod time;
pub mod vfs;

pub use time::ITimerType;

//! [ArceOS] hardware abstraction layer, provides unified APIs for
//! platform-specific operations.
//!
//! It does the bootstrapping and initialization process for the specified
//! platform, and provides useful operations on the hardware.
//!
//! Currently supported platforms (specify by cargo features):
//!
//! - `x86-pc`: Standard PC with x86_64 ISA.
//! - `riscv64-qemu-virt`: QEMU virt machine with RISC-V ISA.
//! - `aarch64-qemu-virt`: QEMU virt machine with AArch64 ISA.
//! - `aarch64-raspi`: Raspberry Pi with AArch64 ISA.
//! - `dummy`: If none of the above platform is selected, the dummy platform
//!   will be used. In this platform, most of the operations are no-op or
//!   `unimplemented!()`. This platform is mainly used for [cargo test].
//!
//! # Cargo Features
//!
//! - `smp`: Enable SMP (symmetric multiprocessing) support.
//! - `fp_simd`: Enable floating-point and SIMD support.

//! [ArceOS](https://github.com/arceos-org/arceos) memory management module.

#![no_std]

#[macro_use]
extern crate log;
extern crate alloc;

mod aspace;
mod backend;
#[cfg(feature = "cow")]
mod frameinfo;

pub mod page_iter_wrapper;
pub use self::aspace::AddrSpace;
pub use self::backend::{Backend, SharedPages};

use axerrno::{AxError, AxResult};
use axhal::mem::phys_to_virt;
use axhal::paging::PageSize;

//! [ArceOS](https://github.com/arceos-org/arceos) task management module.
//!
//! This module provides primitives for task management, including task
//! creation, scheduling, sleeping, termination, etc. The scheduler algorithm
//! is configurable by cargo features.
//!
//! # Cargo Features
//!
//! - `multitask`: Enable multi-task support. If it's enabled, complex task
//!   management and scheduling is used, as well as more task-related APIs.
//!   Otherwise, only a few APIs with naive implementation is available.
//! - `irq`: Interrupts are enabled. If this feature is enabled, timer-based
//!   APIs can be used, such as [`sleep`], [`sleep_until`], and
//!   [`WaitQueue::wait_timeout`].
//! - `preempt`: Enable preemptive scheduling.
//! - `sched_fifo`: Use the [FIFO cooperative scheduler][1]. It also enables the
//!   `multitask` feature if it is enabled. This feature is enabled by default,
//!   and it can be overriden by other scheduler features.
//! - `sched_rr`: Use the [Round-robin preemptive scheduler][2]. It also enables
//!   the `multitask` and `preempt` features if it is enabled.
